import{_ as n,Z as e,P as i,g as d,k as s,m as t}from"./chunks/framework.Dp5g00Bf.js";const f=JSON.parse('{"title":"内存条","description":"","frontmatter":{},"headers":[],"relativePath":"views/3-硬件💻/内存条/index.md","filePath":"views/3-硬件💻/内存条/index.md","lastUpdated":1778336291000}'),l={name:"views/3-硬件💻/内存条/index.md"};function h(c,a,p,_,m,b){const o=e("NolebaseGitContributors"),r=e("NolebaseGitChangelog");return i(),d("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[a[0]||(a[0]=s('<h1 id="内存条" tabindex="-1">内存条 <a class="header-anchor" href="#内存条" aria-label="Permalink to &quot;内存条&quot;">​</a></h1><p>ddr5内存条最重要的数值有三个，分别是容量、频率、时序。</p><h2 id="容量" tabindex="-1">容量 <a class="header-anchor" href="#容量" aria-label="Permalink to &quot;容量&quot;">​</a></h2><p>容量现在推荐32gb，16gb已经无法满足娱乐需求。</p><h2 id="频率" tabindex="-1">频率 <a class="header-anchor" href="#频率" aria-label="Permalink to &quot;频率&quot;">​</a></h2><p>频率AMD平台推荐6000hz，因为高了会分频，意义不大。英特尔平台推荐6800hz及以上。</p><h2 id="时序" tabindex="-1">时序 <a class="header-anchor" href="#时序" aria-label="Permalink to &quot;时序&quot;">​</a></h2><p>时序方面在预算内越低越好，比如c32、c30、c28，我上述列的时序数值越低越好。</p><h2 id="注意⚠️" tabindex="-1">注意⚠️ <a class="header-anchor" href="#注意⚠️" aria-label="Permalink to &quot;注意⚠️&quot;">​</a></h2><p>值得注意的点是ddr5默认频率4800hz，购买高频内存条后，需要在主版内打开xmp或者expo。还有一点，高频内存条需要好的cpu和主板支持，不然可能无法过tm5测试。</p>',10)),t(o),t(r)])}const x=n(l,[["render",h]]);export{f as __pageData,x as default};
